diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..234613330d26 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7159,6 +7159,38 @@ Instruction *InstCombinerImpl::foldICmpCommutative(ICmpInst::Predicate Pred,
     }
   }

+  // (sdiv X, C) < X --> X > 0 (when C > 0)
+  // (sdiv X, C) < X --> X < 0 (when C < 0)
+  // Similar patterns for other predicates.
+  if (ICmpInst::isSigned(Pred)) {
+    Value *X;
+    const APInt *C;
+    if (match(Op0, m_SDiv(m_Value(X), m_APInt(C))) && Op1 == X && !C->isZero()) {
+      Value *NullValue = Constant::getNullValue(X->getType());
+      bool CIsPositive = C->isStrictlyPositive();
+      switch (Pred) {
+      case ICmpInst::ICMP_SLT:
+        return new ICmpInst(CIsPositive ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_SLT,
+                            X, NullValue);
+      case ICmpInst::ICMP_SLE:
+        return new ICmpInst(CIsPositive ? ICmpInst::ICMP_SGE : ICmpInst::ICMP_SLE,
+                            X, NullValue);
+      case ICmpInst::ICMP_SGT:
+        return new ICmpInst(CIsPositive ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_SGT,
+                            X, NullValue);
+      case ICmpInst::ICMP_SGE:
+        return new ICmpInst(CIsPositive ? ICmpInst::ICMP_SLE : ICmpInst::ICMP_SGE,
+                            X, NullValue);
+      case ICmpInst::ICMP_EQ:
+        return new ICmpInst(ICmpInst::ICMP_EQ, X, NullValue);
+      case ICmpInst::ICMP_NE:
+        return new ICmpInst(ICmpInst::ICMP_NE, X, NullValue);
+      default:
+        break;
+      }
+    }
+  }
+
   const SimplifyQuery Q = SQ.getWithInstruction(&CxtI);
   if (Value *V = foldICmpWithLowBitMaskedVal(Pred, Op0, Op1, Q, *this))
     return replaceInstUsesWith(CxtI, V);

